const results = ($.steps.webSearch.response && $.steps.webSearch.response.results) ? $.steps.webSearch.response.results : [];
let sourcesText = '';
const sourceList = [];
results.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 500) + '\n\n';
  sourceList.push({ num: i + 1, title: r.title || 'Untitled', url: r.url });
});
return { sourcesText, sourceList, sourceCount: results.length };

const data = $.steps.compileSources.output;
const question = $.input.question;
const prompt = `You are a knowledgeable research assistant. Answer the following question using the provided web sources.

QUESTION: ${question}

SOURCES:
${data.sourcesText}

Provide a comprehensive, well-sourced answer. Reference source numbers [1], [2], etc. when citing information.

Return ONLY valid JSON:
{
  "answer": "<comprehensive answer with source references like [1], [2]>",
  "confidence": "<high|medium|low>",
  "keyTakeaway": "<single sentence main takeaway>",
  "relatedQuestions": ["<follow-up question 1>", "<follow-up question 2>"]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw.slice(0, 2000), confidence: 'unknown', keyTakeaway: '', relatedQuestions: [] }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const sources = $.steps.compileSources.output.sourceList || [];
const sourceCount = $.steps.compileSources.output.sourceCount;

const confEmoji = { high: ':green_circle:', medium: ':large_orange_circle:', low: ':red_circle:' };

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':mag: Research Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (confEmoji[ai.confidence] || ':white_circle:') + ' *Confidence:* ' + (ai.confidence || 'unknown') } });
blocks.push({ type: 'divider' });

const answer = ai.answer || 'No answer generated.';
const answerChunks = [];
let current = '';
answer.split(' ').forEach(word => {
  if ((current + ' ' + word).length > 2900) {
    answerChunks.push(current);
    current = word;
  } else {
    current = current ? current + ' ' + word : word;
  }
});
if (current) answerChunks.push(current);

answerChunks.forEach(chunk => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: chunk } });
});

blocks.push({ type: 'divider' });

if (ai.keyTakeaway) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':dart: *Key Takeaway:* ' + ai.keyTakeaway } });
}

if (sources.length > 0) {
  let srcText = '*Sources:*\n';
  sources.slice(0, 5).forEach(s => {
    srcText += '[' + s.num + '] <' + s.url + '|' + s.title + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText } });
}

if (ai.relatedQuestions && ai.relatedQuestions.length > 0) {
  let rq = '*Related Questions:*\n';
  ai.relatedQuestions.forEach(q => { rq += ':grey_question: ' + q + '\n'; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: rq }] });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: sourceCount + ' sources analyzed via Exa + Claude AI | One CLI' }] });

const fallback = 'Answer to: ' + question;
return { blocks, fallback };
